# --- API ---
app = Flask(__name__)

# Load the trained model and vectorizer
try:
    vectorizer = joblib.load('vectorizer.joblib')
    model = joblib.load('logistic_regression_model.joblib')
except FileNotFoundError:
    print("Error: Model or vectorizer not found. Please run train_and_save_model() first.")
    exit()

@app.route('/predict_spam', methods=['POST'])
def predict_spam():
    if not request.is_json:
        return jsonify({"error": "Request must be JSON"}), 400

    data = request.get_json()
    email_text = data.get('email_text')

    if not email_text:
        return jsonify({"error": "Missing 'email_text' in request body"}), 400

    # Vectorize the input email text
    email_text_vectorized = vectorizer.transform([email_text])

    # Predict spam probability
    # model.predict_proba returns probabilities for [non-spam, spam]
    spam_probability = model.predict_proba(email_text_vectorized)[:, 1][0]

    return jsonify({"email_text": email_text, "spam_probability": spam_probability})

